// User handler bodies for SmDaemon (STATEM variant).
//
// Generated by gen-app, then hand-edited with sm-specific
// cooperation logic per docs/autosar/services/sm.md §3.B:
//
//   - on_enter mutates SmStateMsg.state + ts_ns and broadcasts to
//     every subscriber registered via subscribe_broadcast_state().
//     Best-effort fan-out (a throwing subscriber doesn't stall the
//     FSM thread).
//   - handle_call(SmRequest) maps an external mode-change request
//     onto the matching FSM event. Targets that are internal-only
//     landing states (RUNNING, OFF, STARTING, DEGRADED) are
//     rejected with a stderr log so the misuse is observable.

#include "lib/SmDaemon.hh"

#include <chrono>
#include <cstdio>

namespace ara::sm {

static uint64_t now_ns_() {
    auto now = std::chrono::steady_clock::now().time_since_epoch();
    return static_cast<uint64_t>(
        std::chrono::duration_cast<std::chrono::nanoseconds>(now).count());
}

void SmDaemon::on_enter(SmDaemonState new_s,
                          SmDaemonState /*old_s*/,
                          SmDaemonData& d) {
    // SmDaemonData IS SmStateMsg (alias produced by the lib template
    // because the .art's statem block declared `data SmStateMsg`). So
    // mutating d here updates the broadcast payload + the FSM's
    // persistent data in one move.
    d.state = static_cast<services_services_sm_SmState>(new_s);
    d.ts_ns = now_ns_();

    // Diagnostic — the supervisor's per-child log capture surfaces
    // this in the GUI's Trace panel.
    static const char* names[] = {
        "OFF", "STARTING", "RUNNING", "DEGRADED", "UPDATE", "SHUTDOWN",
    };
    const auto idx = static_cast<std::size_t>(new_s);
    std::fprintf(stderr, "[%s] → %s @ %llu\n",
                 kNodeName,
                 idx < sizeof(names)/sizeof(names[0]) ? names[idx] : "?",
                 static_cast<unsigned long long>(d.ts_ns));

    // §3.B notifier: fan out to every registered SmStateStream
    // subscriber. The lib template's broadcast_broadcast_state()
    // snapshots subscribers under the lock + invokes outside it, so
    // a slow subscriber can't stall the FSM thread.
    broadcast_broadcast_state(d);
}

// StateMgmtCtl::RequestMode — map an external mode-change request
// onto the matching FSM event. Caller is typically UCM (UpdateMode)
// or whatever app holds a StateMgmtCtl client.
//
// RUNNING is reached via internal events (StartupComplete,
// UpdateComplete) — not via a direct request. OFF/STARTING/DEGRADED
// are likewise internal-only landing states. Reject those with a
// stderr log so misuse is observable.
SmEmpty SmDaemon::handle_call(
        const SmRequest& req,
        demo::runtime::GenStateMHolder<SmDaemonState, SmDaemonData>& /*h*/) {
    switch (req.target) {
    case services_services_sm_SmState_SHUTDOWN:
        demo::runtime::post_event(*this, ShutdownRequest{});
        break;
    case services_services_sm_SmState_UPDATE:
        demo::runtime::post_event(*this, UpdateRequest{});
        break;
    case services_services_sm_SmState_RUNNING:
        std::fprintf(stderr,
            "[%s] RequestMode(RUNNING) — RUNNING is reached via "
            "internal events; request ignored\n", kNodeName);
        break;
    default:
        std::fprintf(stderr,
            "[%s] RequestMode(target=%u) — not a client-driven "
            "target; request ignored\n",
            kNodeName, static_cast<unsigned>(req.target));
        break;
    }
    return SmEmpty{};
}

}  // namespace ara::sm
